    public boolean validateWrite()
    {
        boolean ret;

        // Aqui vai a linha obrigatória que chama a lógica original (o "pai")
        ret = next validateWrite();
        CustParameters custParameters = CustParameters::find();

        if (ret) //Se a microsofot aprovou...
        {   // Aqui uso a variável carregada e comparo com o check noyes = yes
            if (this.CreditMax > custParameters::find().ABCCreditLimitThreshold && custParameters.ABCAtivarValidacaoVIP == NoYes::Yes) {
                    ret = checkFailed(strFmt("@EtiquetasMensagens:ErroLimiteExcedido", custParameters::find().ABCCreditLimitThreshold));
            }
        }

        return ret;
    }
